// Ghiath reminder acknowledge handler. The ntfy alarm carries an "Acknowledge"
// button that POSTs to this webhook (/webhook/reminder-ack?id=<id>). Flipping the
// note's status to "acknowledged" stops the scheduler from nagging further.
const fs = require('fs');
const path = require('path');

const DIR = '/data/vault/reminders';
const q = $input.first().json.query || {};
const id = q.id || $input.first().json.id;
if (!id) return [{ json: { ok: false, error: 'no id' } }];

let files = [];
try {
  files = fs.readdirSync(DIR).filter((f) => f.endsWith('.md'));
} catch (e) {
  return [{ json: { ok: false, error: 'no reminders folder' } }];
}

for (const file of files) {
  const fp = path.join(DIR, file);
  let raw;
  try { raw = fs.readFileSync(fp, 'utf8'); } catch (e) { continue; }
  const m = raw.match(/^---\n([\s\S]*?)\n---/);
  if (!m) continue;
  const fid = ((m[1].match(/^id:\s*(.*)$/m) || [])[1] || file.replace(/\.md$/, '')).trim();
  if (fid !== id) continue;

  let block = m[1];
  block = /^status:/m.test(block)
    ? block.replace(/^status:.*$/m, 'status: acknowledged')
    : block + '\nstatus: acknowledged';
  block = /^ackedAt:/m.test(block)
    ? block.replace(/^ackedAt:.*$/m, 'ackedAt: ' + new Date().toISOString())
    : block + '\nackedAt: ' + new Date().toISOString();

  const rebuilt = raw.replace(/^---\n[\s\S]*?\n---/, '---\n' + block + '\n---');
  try { fs.writeFileSync(fp, rebuilt); } catch (e) { /* ignore */ }
  return [{ json: { ok: true, id, status: 'acknowledged' } }];
}

return [{ json: { ok: false, error: 'reminder not found', id } }];
